module RefModule(
   input                clk,
   input                rst,

   output reg [2:0]     count  
);
  wire _tap_clk = clk & {1{1'b1}};

    always@(posedge clk) begin
        if(rst) 
            count <= 3'b111; // Reset counter to 7
        else 
            count <= count - 1;
    end
endmodule
